INSERT OR REPLACE INTO "search_index" ("id", "content_type", "title", "content", "subject", "tags", "importance", "created_at") VALUES
  ('2c847b3c-30f0-4b29-842e-1925e339df0b', '理论', '议程设置理论', '麦库姆斯和肖（1972）提出。大众媒介可以通过反复报道来赋予议题不同程度的显著性，影响公众对议题重要性的判断。', '440', '议程设置,效果研究', 5, '2026-06-09 12:54:13'),
  ('8303fd28-103b-4f0d-b6b7-65ce52d7518d', '理论', '沉默的螺旋', '诺依曼（1974）提出。人们在表达观点时会观察舆论环境，如果发现自己的观点属于少数派，出于被孤立的恐惧，会倾向于沉默。', '440', '沉默的螺旋,舆论', 5, '2026-06-09 12:54:13'),
  ('7ff21ff4-428b-46c6-94ad-1cf51091b63b', '理论', '知沟理论', '蒂奇诺等（1970）提出。随着大众传播的信息量增加，社会经济地位较高的人获取知识的速度快于地位低的人。', '440', '知沟,信息差距', 5, '2026-06-09 12:54:13'),
  ('875c8968-0cda-43d6-ab6d-16f30a380436', '理论', '使用与满足理论', '卡茨（1974）提出。受众是主动的，基于特定需求选择和使用媒介来获得满足。', '440', '使用与满足,受众', 5, '2026-06-09 12:54:13'),
  ('6bc3400f-a104-44eb-b2c5-c22b566d2620', '理论', '把关人理论', '卢因（1947）提出。信息在传播过程中需要经过把关人的筛选和过滤。', '440', '把关人,信息过滤', 5, '2026-06-09 12:54:13'),
  ('62fa9603-8aba-4ecb-8a15-b1012c2289c2', '理论', '框架理论', '戈夫曼（1974）提出框架概念，恩特曼引入传播学。媒体通过选择、强调和排除来建构报道框架。', '440', '框架,议程设置', 5, '2026-06-09 12:54:13'),
  ('1655545e-560c-4bc5-b32f-e58c5cf4a119', '理论', '培养理论', '格伯纳（1960s）提出。大众传媒通过长期的、潜移默化的影响，会塑造受众对现实世界的认知。', '440', '培养理论,电视', 5, '2026-06-09 12:54:13'),
  ('af1a3493-9cd4-43f4-af3a-70fdbcc1f7cc', '理论', '信息茧房', '桑斯坦（2001）提出。在信息传播中，公众只关注自己选择的或使自己愉悦的信息。', '440', '信息茧房,算法', 5, '2026-06-09 12:54:13'),
  ('9cdb3f12-c0ab-4920-97c7-cda341545738', '理论', '编码/解码', '霍尔（1973）提出。媒介文本由传播者编码，由受众解码。三种解码立场。', '440', '编码解码,文化研究', 5, '2026-06-09 12:54:13'),
